// tests/user_code_tests_901.cpp#include <gtest/gtest.h>#include <gmock/gmock.h>#include <memory>#include <stdexcept>#include "Catch2/extras/catch_amalgamated.hpp"using ::testing::Return;using ::testing::Exactly;namespace {struct MockFunctor {    MOCK_METHOD(int, operator(), (), ());};struct MoveOnlyFunctor {    MoveOnlyFunctor() = default;    MoveOnlyFunctor(const MoveOnlyFunctor&) = delete;    MoveOnlyFunctor& operator=(const MoveOnlyFunctor&) = delete;    MoveOnlyFunctor(MoveOnlyFunctor&&) = default;    MoveOnlyFunctor& operator=(MoveOnlyFunctor&&) = default;    int operator()() { return 123; }};class UserCodeTest_901 : public ::testing::Test {};} // namespace// Normal operation: returns a value as-isTEST_F(UserCodeTest_901, ReturnsInt_901) {    auto lambda = [] { return 42; };    int out = Catch::Benchmark::user_code(lambda);    EXPECT_EQ(out, 42);}// Normal operation: supports void-returning callable with visible side effectTEST_F(UserCodeTest_901, VoidCallableSideEffect_901) {    bool flag = false;    auto lambda = [&] { flag = true; };    Catch::Benchmark::user_code(lambda);    EXPECT_TRUE(flag);}// Exceptional case: exceptions from the callable propagateTEST_F(UserCodeTest_901, ExceptionPropagates_901) {    auto lambda = []() -> int {        throw std::runtime_error("boom");    };    EXPECT_THROW(Catch::Benchmark::user_code(lambda), std::runtime_error);}// Boundary: move-only return type is supported and preservedTEST_F(UserCodeTest_901, MoveOnlyReturn_901) {    auto lambda = [] { return std::make_unique<int>(7); };    std::unique_ptr<int> p = Catch::Benchmark::user_code(lambda);    ASSERT_NE(p, nullptr);    EXPECT_EQ(*p, 7);}// Boundary: reference return is preserved (mutation via returned ref reflects externally)TEST_F(UserCodeTest_901, ReturnsReference_901) {    int value = 10;    auto lambda = [&]() -> int& { return value; };    int& ref = Catch::Benchmark::user_code(lambda);    ref = 99;    EXPECT_EQ(value, 99);}// Verification of external interaction: invoking a mock functor calls its operator()TEST_F(UserCodeTest_901, InvokesMockFunctor_901) {    MockFunctor mock;    EXPECT_CALL(mock, operator()())        .Times(Exactly(1))        .WillOnce(Return(314));    int out = Catch::Benchmark::user_code(mock);    EXPECT_EQ(out, 314);}// Boundary: callable itself is move-only (perfect forwarding works)TEST_F(UserCodeTest_901, SupportsMoveOnlyFunctor_901) {    MoveOnlyFunctor f;    int out = Catch::Benchmark::user_code(std::move(f));    EXPECT_EQ(out, 123);}